parameters.jsCode:
// Extract performance data
const eventData = $input.first().json;
const userId = eventData.user_id;
const eventType = eventData.event_type;
const performanceData = eventData.data;

// Determine intervention level
let interventionLevel = 'gentle';
let supportMessage = '';
let recommendedActions = [];

if (eventType === 'quiz.failed') {
  const score = performanceData.score || 0;
  if (score < 40) {
    interventionLevel = 'intensive';
    supportMessage = "Don't worry! Learning takes time. Let's focus on the basics and build from there. 🌱";
    recommendedActions = ['review_fundamentals', 'practice_exercises', 'one_on_one_support'];
  } else if (score < 60) {
    interventionLevel = 'moderate';
    supportMessage = "You're making progress! Let's review a few key concepts to boost your confidence. 💪";
    recommendedActions = ['targeted_review', 'practice_quiz', 'study_tips'];
  }
} else if (eventType === 'performance.low_detected') {
  const avgScore = performanceData.average_score || 0;
  interventionLevel = avgScore < 50 ? 'intensive' : 'moderate';
  supportMessage = "I noticed you might be struggling with some concepts. Let's work together to improve! 🤝";
  recommendedActions = ['skill_assessment', 'personalized_lesson_plan', 'extra_support'];
}

// Areas needing attention
const strugglingAreas = performanceData.struggling_areas || performanceData.areas_to_review || [];

return [{
  json: {
    user_id: userId,
    intervention_level: interventionLevel,
    support_message: supportMessage,
    recommended_actions: recommendedActions,
    struggling_areas: strugglingAreas,
    performance_score: performanceData.score || performanceData.average_score || 0,
    event_type: eventType,
    timestamp: new Date().toISOString()
  }
}];

