// Schedule follow-up check in 3 days
const followUpDate = new Date();
followUpDate.setDate(followUpDate.getDate() + 3);

return [{
  json: {
    user_id: $input.first().json.user_id,
    follow_up_date: followUpDate.toISOString(),
    check_type: 'performance_follow_up',
    intervention_applied: true,
    original_score: $input.first().json.performance_score,
    intervention_level: $input.first().json.intervention_level
  }
}];

